// Niantic-style data schema + sample data
// Generated by GitHub Copilot assistant for jkgb92-png/The-real-earth

export type NianticPOIType = 'pokestop' | 'gym' | 'portal' | 'event' | 'poi' | string;

export interface NianticData {
  id: string;                     // unique identifier
  name: string;                   // display name
  description?: string;           // optional description
  type: NianticPOIType;           // POI type
  location: {
    lat: number;
    lng: number;
    alt?: number;
  };
  tags?: string[];                // e.g., ["historic", "art"]
  properties?: Record<string, any>; // arbitrary provider-specific fields
  updatedAt?: string;             // ISO timestamp
}

// Example sample data
