// Helper: convert NianticData -> GeoJSON Feature
export function toGeoJSONFeature(item: NianticData) {
  return {
    type: "Feature",
    geometry: {
      type: "Point",
      coordinates: [item.location.lng, item.location.lat]
    },
    properties: {
      id: item.id,
      name: item.name,
      description: item.description,
      type: item.type,
      tags: item.tags,
      ...item.properties,
      updatedAt: item.updatedAt
    }
  };
}

// Helper: FeatureCollection
export function toFeatureCollection(items: NianticData[]) {
  return {
    type: "FeatureCollection",
    features: items.map(toGeoJSONFeature)
  };
}

export default nianticData;
